// frontend/src/event/EventDetail.js
import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';

const EventDetail = () => {
  const { id } = useParams(); // URLからイbytes:\xe3\x83bytes:\x99ントIDを取得
  const [event, setEvent] = useState(null);
  //bytes: \xe7bytes:\xb7\xa8集用のbytes:\xe7bytes:\x8a\xb6bytes:\xe6bytes:\x85bytes:\x8bをbytes:\xe8\xbfbytes:\xbd加
  const [editEvent, setEditEvent] = useState({ event_name: '', event_info: '' });

  useEffect(() => {
    //イbytes:\xe3\x83bytes:\x99ントIDに基bytes:\xe3\x81bytes:\xa5いてイbytes:\xe3\x83bytes:\x99ントの情報を取得するロジックをここに装bytes:\xe5bytes:\x82bytes:\x99
    const fetchEventDetail = async () => {
      const response = await fetch(`http://localhost:8000/event/get?event_id=${id}`);
      const data = await response.json();
      setEvent(data[0]); //イbytes:\xe3\x83bytes:\x99ントの情報をbytes:\xe8\xa8bytes:\xad定
      //取得したイbytes:\xe3\x83bytes:\x99ント情報をbytes:\xe7bytes:\xb7\xa8集用のbytes:\xe7bytes:\x8a\xb6bytes:\xe6bytes:\x85bytes:\x8bにもbytes:\xe8\xa8bytes:\xad定
      setEditEvent({ event_name: data[0].event_name, event_info: data[0].event_info });
    };

    fetchEventDetail();
  }, [id]);

  //bytes:\xe7bytes:\xb7\xa8集を保存する関数
  const saveEdit = async () => {
    await fetch(`http://localhost:8000/event/edit/${id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editEvent)
    });
    //bytes:\xe7bytes:\xb7\xa8集後のイbytes:\xe3\x83bytes:\x99ント情報を再取得
    setEvent(editEvent);
  };

  if (!event) {
    return <div>Loading...</div>;
  }

  return (
    <div>
      <h1>イbytes:\xe3\x83bytes:\x99ントbytes:\xe8\xa9bytes:\xb3bytes:\xe7\xb4bytes:\xb0bytes:\xe7bytes:\xb7\xa8集</h1>
      <label>
       bytes: \xe3\x82bytes:\xa4bytes:\xe3\x83bytes:\x99ント名:
        <input
          type="text"
          value={editEvent.event_name}
          onChange={(e) => setEditEvent({ ...editEvent, event_name: e.target.value })}
        />
      </label>
      <label>
       bytes: \xe3\x82bytes:\xa4bytes:\xe3\x83bytes:\x99ント内容:
        <input
          type="text"
          value={editEvent.event_info}
          onChange={(e) => setEditEvent({ ...editEvent, event_info: e.target.value })}
        />
      </label>
      <button onClick={saveEdit}>保存</button>
    </div>
  );
};

export default EventDetail;
